create table dirkspzm32.isi_rave_projekte_cfg (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(6, 0) not null enable,
    kategorie            varchar2(100 char) not null enable,
    rave_projekt         varchar2(255 char) not null enable,
    rave_report_namen_cs varchar2(2000 char),
    projekt_pfad         varchar2(2000 char),
    projekt_ablage       varchar2(10 char) default 'FN' not null enable,
    beschreibung         varchar2(255 char)
);

alter table dirkspzm32.isi_rave_projekte_cfg
    add constraint pk_rave_projekte_cfg
        primary key ( sid,
                      firma_nr,
                      kategorie,
                      rave_projekt )
            using index enable;


